/**
 * Removes the tautological "Has expected section structure" goal checks.
 *
 * These were generated by slicing a page's OWN current H2 headings, so the
 * check only asserts "the page has the headings it currently has" — it encodes
 * no intended structure and passes trivially. Curated structure checks with
 * prescriptive labels (e.g. "Has standard example page sections",
 * "Covers core concept categories") are left untouched.
 *
 * Usage:
 *   node scripts/remove-tautological-checks.mjs          # dry run
 *   node scripts/remove-tautological-checks.mjs --apply  # write changes
 */

import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import matter from 'gray-matter';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const CONTENT_ROOT = path.resolve(__dirname, '..', '..', 'content');
const dryRun = !process.argv.includes('--apply');

const DROP_LABEL = 'Has expected section structure';

function globMdx(dir) {
  const results = [];
  function walk(d) {
    for (const entry of fs.readdirSync(d, { withFileTypes: true })) {
      const full = path.join(d, entry.name);
      if (entry.isDirectory()) {
        if (['node_modules', '.docusaurus', 'build', 'dist'].includes(entry.name)) continue;
        walk(full);
      } else if (entry.name.endsWith('.mdx')) {
        results.push(full);
      }
    }
  }
  walk(dir);
  return results;
}

let updated = 0;
let removed = 0;

for (const filePath of globMdx(CONTENT_ROOT)) {
  const raw = fs.readFileSync(filePath, 'utf8');
  const { data, content: body } = matter(raw);
  if (!data.goal || !Array.isArray(data.goal.requires)) continue;

  const before = data.goal.requires.length;
  data.goal.requires = data.goal.requires.filter(
    (r) => !(r && r.headings && r.label === DROP_LABEL)
  );
  const dropped = before - data.goal.requires.length;
  if (dropped === 0) continue;

  removed += dropped;
  updated++;
  if (dryRun) {
    console.log(`${path.relative(CONTENT_ROOT, filePath)} — drop ${dropped}`);
  } else {
    fs.writeFileSync(filePath, matter.stringify(body, data), 'utf8');
  }
}

console.log(`${'─'.repeat(50)}`);
console.log(`${dryRun ? 'DRY RUN' : 'APPLIED'}  pages=${updated} checks_removed=${removed}`);
if (dryRun) console.log('Run with --apply to write changes.');
